// Custom alchemy Resource for AWS ALB Listener.
// Generated by stackpanel — static library code.
import type { Context } from "alchemy";
import { Resource } from "alchemy";

export interface ListenerProps {
  loadBalancerArn: string;
  port: number;
  protocol: "HTTP" | "HTTPS" | "TCP";
  sslPolicy?: string;
  certificateArn?: string;
  defaultTargetGroupArn: string;
  destroyOnDelete?: boolean;
}

export interface Listener {
  arn: string;
  port: number;
  protocol: string;
  adopted?: boolean;
}

export const Listener = Resource(
  "stackpanel::Listener",
  async function (
    this: Context<Listener>,
    _id: string,
    props: ListenerProps,
  ): Promise<Listener> {
    const {
      ElasticLoadBalancingV2Client,
      DescribeListenersCommand,
      CreateListenerCommand,
      DeleteListenerCommand,
    } = await import("@aws-sdk/client-elastic-load-balancing-v2");

    const client = new ElasticLoadBalancingV2Client({});

    if (this.phase === "delete") {
      if (props.destroyOnDelete === false) {
        return this.destroy();
      }
      if (this.output?.arn) {
        try {
          await client.send(new DeleteListenerCommand({ ListenerArn: this.output.arn }));
        } catch (err: any) {
          if (err.name !== "ListenerNotFound") throw err;
        }
      }
      return this.destroy();
    }

    let arn = this.output?.arn;
    let adopted = this.output?.adopted ?? false;

    if (!arn) {
      const existing = await client.send(
        new DescribeListenersCommand({ LoadBalancerArn: props.loadBalancerArn }),
      );
      const found = (existing.Listeners ?? []).find(
        (listener) =>
          listener.Port === props.port &&
          listener.Protocol === props.protocol,
      );
      if (found?.ListenerArn) {
        arn = found.ListenerArn;
        adopted = true;
      }
    }

    if (!arn) {
      const created = await client.send(
        new CreateListenerCommand({
          LoadBalancerArn: props.loadBalancerArn,
          Port: props.port,
          Protocol: props.protocol,
          Certificates: props.certificateArn
            ? [{ CertificateArn: props.certificateArn }]
            : undefined,
          SslPolicy: props.sslPolicy,
          DefaultActions: [
            {
              Type: "forward",
              TargetGroupArn: props.defaultTargetGroupArn,
            },
          ],
        }),
      );
      const listener = created.Listeners?.[0];
      if (!listener?.ListenerArn) {
        throw new Error(`Unable to create listener on port ${props.port}`);
      }
      arn = listener.ListenerArn;
    }

    if (!arn) {
      throw new Error(`Unable to resolve listener on port ${props.port}`);
    }

    return {
      arn,
      port: props.port,
      protocol: props.protocol,
      adopted,
    };
  },
);
